import type { Meta, StoryObj } from '@storybook/react-vite';
import { Link } from './Link';
import { Space } from '../Space';
import { EditGlyph } from '../../stories/icons';

const meta = {
  title: 'Components/Link',
  component: Link,
  tags: ['autodocs'],
  argTypes: {
    type: {
      control: 'select',
      options: ['default', 'primary', 'success', 'warning', 'danger', 'info'],
    },
    underline: { control: 'boolean' },
    disabled: { control: 'boolean' },
    href: { control: 'text' },
    icon: { control: false },
  },
  args: {
    children: 'Cobos UI',
    type: 'primary',
    href: '#',
  },
} satisfies Meta<typeof Link>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {};

export const Types: Story = {
  render: () => (
    <Space wrap>
      <Link href="#">Default</Link>
      <Link href="#" type="primary">
        Primary
      </Link>
      <Link href="#" type="success">
        Success
      </Link>
      <Link href="#" type="warning">
        Warning
      </Link>
      <Link href="#" type="danger">
        Danger
      </Link>
      <Link href="#" type="info">
        Info
      </Link>
    </Space>
  ),
};

export const WithIcon: Story = {
  name: 'With icon',
  render: () => (
    <Space wrap>
      <Link href="#" type="primary" icon={EditGlyph}>
        Edit
      </Link>
      <Link href="#" type="primary" underline={false}>
        No underline
      </Link>
      <Link href="#" disabled>
        Disabled
      </Link>
    </Space>
  ),
};

import {
  type AnchorHTMLAttributes,
  forwardRef,
  type MouseEvent,
  type ReactNode,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { Icon } from '../Icon';

export type LinkType = 'default' | 'primary' | 'success' | 'warning' | 'danger' | 'info';

export interface LinkProps extends AnchorHTMLAttributes<HTMLAnchorElement> {
  /** Visual variant. */
  type?: LinkType;
  /** Show an underline on hover. */
  underline?: boolean;
  /** Disable the link (removes `href` and blocks interaction). */
  disabled?: boolean;
  /** Destination URL. Ignored when disabled. */
  href?: string;
  /** Where to open the linked document. */
  target?: string;
  /** Leading icon. */
  icon?: ReactNode;
  children?: ReactNode;
}

export const Link = forwardRef<HTMLAnchorElement, LinkProps>(function Link(props, ref) {
  const {
    type = 'default',
    underline = true,
    disabled = false,
    href,
    target,
    icon,
    className,
    style,
    children,
    onClick,
    ...rest
  } = props;

  const ns = useNamespace('link');

  // An anchor has no native `disabled` attribute, so when disabled we must
  // guard the click ourselves: block default navigation and suppress the
  // consumer's handler. Stripping `href` only prevents navigation, not the
  // firing of `onClick`/other handlers.
  const handleClick = (event: MouseEvent<HTMLAnchorElement>) => {
    if (disabled) {
      event.preventDefault();
      return;
    }
    onClick?.(event);
  };

  const classes = cls(
    ns.b(),
    type && type !== 'default' && ns.m(type),
    ns.is('underline', underline && !disabled),
    ns.is('disabled', disabled),
    className,
  );

  return (
    <a
      ref={ref}
      className={classes}
      href={disabled ? undefined : href}
      target={disabled ? undefined : target}
      aria-disabled={disabled || undefined}
      style={style}
      onClick={handleClick}
      {...rest}
    >
      {icon && <Icon className={ns.e('icon')}>{icon}</Icon>}
      {children !== undefined && children !== null && (
        <span className={ns.e('inner')}>{children}</span>
      )}
    </a>
  );
});

.ec-link {
  --ec-link-text-color: var(--ec-text-color-regular);
  --ec-link-hover-text-color: var(--ec-color-primary);
  --ec-link-disabled-text-color: var(--ec-disabled-text-color);

  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  gap: 4px;
  padding: 0;
  font-family: inherit;
  font-size: var(--ec-font-size-base);
  font-weight: var(--ec-font-weight-primary);
  line-height: 1;
  cursor: pointer;
  text-decoration: none;
  color: var(--ec-link-text-color);
  background: none;
  border: none;
  outline: none;
  transition: var(--ec-transition-color);
}

.ec-link:hover {
  color: var(--ec-link-hover-text-color);
}

.ec-link:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: 2px;
  border-radius: var(--ec-border-radius-small);
}

.ec-link__inner {
  display: inline-flex;
  align-items: center;
}

/* The underline sits under the inner text only, shown on hover. */
.ec-link.is-underline:hover .ec-link__inner::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 0;
  border-bottom: 1px solid var(--ec-link-hover-text-color);
}

.ec-link.is-underline:hover .ec-link__inner {
  position: relative;
}

/* ---- Type variants ---- */
.ec-link--primary {
  --ec-link-text-color: var(--ec-color-primary);
  --ec-link-hover-text-color: var(--ec-color-primary-light-3);
}

.ec-link--success {
  --ec-link-text-color: var(--ec-color-success);
  --ec-link-hover-text-color: var(--ec-color-success-light-3);
}

.ec-link--warning {
  --ec-link-text-color: var(--ec-color-warning);
  --ec-link-hover-text-color: var(--ec-color-warning-light-3);
}

.ec-link--danger {
  --ec-link-text-color: var(--ec-color-danger);
  --ec-link-hover-text-color: var(--ec-color-danger-light-3);
}

.ec-link--info {
  --ec-link-text-color: var(--ec-color-info);
  --ec-link-hover-text-color: var(--ec-color-info-light-3);
}

/* ---- Disabled ---- */
.ec-link.is-disabled,
.ec-link.is-disabled:hover {
  color: var(--ec-link-disabled-text-color);
  cursor: not-allowed;
}
